class MyCustomJSONHandler(json.JSONEncoder):
    def default(self, obj: object) -> object:
        if isinstance(obj, np.ndarray):
            flat_values = obj.ravel()
            nan_mask = np.isnan(flat_values)
            unique_non_nan = np.unique(flat_values[~nan_mask]).tolist()
            unique_nan = flat_values[nan_mask].tolist()
            return unique_non_nan + unique_nan
        return super().default(obj)


